SELECT max( id ) AS id, count( ip ) AS ip FROM access_management where 1=1
and date_format( create_time, '%Y-%m-%d' ) >= #{accessManagementModel.startCreateTime}
and date_format( create_time, '%Y-%m-%d' ) <= #{accessManagementModel.endCreateTime}
and origin_id = #{accessManagementModel.originId}
GROUP BY ip

